function getState(){
  return JSON.parse(localStorage.getItem(VERSION)||'{"lesson":0,"done":[],"xp":0,"answers":{},"wrong":[],"mock":null}');
}
function setState(s){ localStorage.setItem(VERSION, JSON.stringify(s)); }
function reset(){ if(confirm('v1.0βの進捗を初期化しますか？')){ localStorage.removeItem(VERSION); sessionStorage.clear(); location.href='index.html'; } }
function shuffle(arr){ return arr.map(v=>[Math.random(),v]).sort((a,b)=>a[0]-b[0]).map(x=>x[1]); }
function pct(n,d){ return d?Math.round(n/d*100):0; }
function clamp(n,min,max){ return Math.max(min, Math.min(max,n)); }
function lessonById(id){ return lessons.find(l=>l.id===id); }
function escapeReg(s){ return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }
function showToast(t){ const old=document.querySelector('.toast'); if(old) old.remove(); const el=document.createElement('div'); el.className='toast'; el.textContent=t; document.body.appendChild(el); setTimeout(()=>el.classList.add('show'),10); setTimeout(()=>el.classList.remove('show'),1700); }

function answerStats(s){
  const vals=Object.values(s.answers||{});
  const answered=vals.length;
  const correct=vals.filter(a=>a.lastCorrect).length;
  const totalAttempts=vals.reduce((sum,a)=>sum+(a.attempts||0),0);
  return {answered, correct, accuracy:pct(correct, answered), totalAttempts};
}
function passRate(s){
  const st=answerStats(s);
  const lessonComponent = pct(s.done.length, lessons.length) * 0.45;
  const confidence = Math.min(st.answered / 80, 1);
  const answerComponent = (st.accuracy||0) * confidence * 0.45;
  const mockBonus = s.mock && s.mock.rate ? Math.min(s.mock.rate*0.10, 10) : 0;
  return Math.round(clamp(lessonComponent + answerComponent + mockBonus, 0, 100));
}
function passNote(s){ const st=answerStats(s); if(st.answered<10) return 'まだ判定材料が少なめ'; if(st.accuracy>=80) return '問題精度は良好'; if(st.accuracy>=60) return '合格圏へ近づいています'; return '復習優先'; }
function recordAnswer(q, correct){
  const s=getState();
  s.answers[q.id]={area:q.area,type:q.type,lastCorrect:correct,attempts:((s.answers[q.id]&&s.answers[q.id].attempts)||0)+1,updated:Date.now()};
  if(!correct && !s.wrong.includes(q.id)) s.wrong.push(q.id);
  if(correct) s.wrong=s.wrong.filter(id=>id!==q.id);
  setState(s);
}
function chapterProgress(ch, s){ const done = ch.lessons.filter(id=>s.done.includes(lessons.findIndex(l=>l.id===id))).length; return {done,total:ch.lessons.length,pct:pct(done,ch.lessons.length)}; }
function currentChapter(s){ const l=lessons[Math.min(s.lesson,lessons.length-1)]; return chapters.find(c=>c.title===l.chapter)||chapters[0]; }
function chapterDisplay(c,s){
  const current=currentChapter(s); const p=chapterProgress(c,s);
  if(c.id===current.id){
    const curId=lessons[Math.min(s.lesson,lessons.length-1)].id; const pos=Math.max(1,c.lessons.indexOf(curId)+1);
    return {label:`現在 ${pos}/${c.lessons.length}（完了${p.done}）`, barPct:pct(pos-1,c.lessons.length), done:p.done,total:p.total};
  }
  if(p.done>=p.total) return {label:'完了', barPct:100, done:p.done,total:p.total};
  return {label:`未着手 ${p.done}/${p.total}`, barPct:p.pct, done:p.done,total:p.total};
}
function nav(active){ const items=[['index.html','ホーム'],['study.html','学習'],['quiz.html','問題'],['mock.html','模試'],['profile.html','記録']]; return `<nav class="nav"><div class="nav-inner">${items.map(i=>`<a href="${i[0]}" class="${i[1]===active?'active':''}">${i[1]}</a>`).join('')}</div></nav>`; }
function header(){ return `<div class="top"><a class="brand" href="index.html">UXPASS</a><span class="pill">${APP_LABEL}</span></div>`; }
function highlight(text, terms){ let html=text.replace(/\n/g,'<br><br>'); [...terms].sort((a,b)=>b.length-a.length).forEach(t=>{ const re=new RegExp(escapeReg(t),'g'); html=html.replace(re,`<button class=\"term\" onclick=\"openTerm('${t}')\">${t}</button>`); }); return html; }
function openTerm(t){ const d=termDict[t]||{title:t,desc:'この用語は今後追加予定です。',tags:['追加予定']}; const el=document.createElement('div'); el.className='modal-back'; el.innerHTML=`<div class="modal"><button class="modal-close" onclick="this.closest('.modal-back').remove()">×</button><h2>${d.title}</h2><p class="content">${d.desc}</p>${d.compare?`<div class="explain"><b>違いのポイント</b><br>${d.compare}</div>`:''}<div>${(d.tags||[]).map(x=>`<span class="tag">${x}</span>`).join('')}</div></div>`; document.body.appendChild(el); }

function renderHome(){
 const s=getState(); const idx=Math.min(s.lesson,lessons.length-1); const l=lessons[idx]; const st=answerStats(s); const pr=passRate(s); const ch=currentChapter(s);
 const road=chapters.map(c=>{ const d=chapterDisplay(c,s); return `<div class="road-row ${c.id===ch.id?'now':''}"><div><b>${c.title}</b><p>${c.goal}</p><p><span class="tag">${d.label}</span><span class="tag">${c.status==='complete-beta'?'β完成品質':c.status==='next'?'次に強化':'土台'}</span></p></div><div style="min-width:86px"><div class="mini-meter"><div style="width:${d.barPct}%"></div></div></div></div>`; }).join('');
 document.body.innerHTML=`<main class="app">${header()}<section class="hero"><div class="small">今日の続き</div><h1>${l.title}</h1><p class="sub">${l.chapter}・約${l.minutes}分<br>合格予測：${pr}%（${passNote(s)}）</p><div class="meter"><div class="bar" style="width:${pct(s.done.length,lessons.length)}%"></div></div><button class="btn" onclick="location.href='study.html'">続きから学習</button></section><section class="grid"><div class="mini"><b>${pr}%</b><span class="small">合格予測</span></div><div class="mini"><b>${st.accuracy||0}%</b><span class="small">問題正答率<br>${st.answered}問回答</span></div><div class="mini"><b>${s.done.length}/${lessons.length}</b><span class="small">完了レッスン</span></div><div class="mini"><b>${questions.filter(q=>q.area==='UX概論').length}</b><span class="small">Chapter1問題</span></div></section><section class="card"><div class="section-head"><div><b>ロードマップ</b><p class="small">全6章。いまはChapter1を完成品質に強化中。</p></div><a class="pill" href="search.html">対応表</a></div>${road}</section><button class="btn secondary" onclick="sessionStorage.setItem('randomQidx','0');location.href='quiz.html?mode=random'">問題演習へ</button><button class="btn ghost" onclick="reset()">進捗を初期化</button></main>${nav('ホーム')}`;
}

function renderStudy(){
 const s=getState(); const idx=Math.min(s.lesson,lessons.length-1); const l=lessons[idx]; const ch=chapters.find(c=>c.title===l.chapter); const cp=chapterProgress(ch,s); const curPos=ch.lessons.indexOf(l.id)+1; const isChapterEnd=curPos===ch.lessons.length;
 document.body.innerHTML=`<main class="app">${header()}<section class="card"><div class="small">${l.chapter} / Lesson ${curPos} of ${ch.lessons.length}</div><h1 class="lesson-title">${l.title}</h1><div class="meter"><div class="bar" style="width:${pct(idx,lessons.length)}%"></div></div><div class="map-note"><b>この章の位置づけ</b><br>${ch.goal}<br><span>現在 ${curPos}/${ch.lessons.length}・完了 ${cp.done}/${cp.total}</span></div><p class="content lead">${l.intro}</p><p class="content">${highlight(l.body,l.terms)}</p><div>${l.terms.map(t=>`<button class="tag tagbtn" onclick="openTerm('${t}')">${t}</button>`).join('')}</div><div class="source-line">対応：${(l.syllabus||[]).map(x=>`<span class="tag">${x}</span>`).join('')}</div></section>${isChapterEnd ? `<section class="card"><div class="section-title" style="margin-top:0">章末チェック</div><p class="content">この章で学んだ内容をケース問題で確認します。Chapter1は本番寄せ問題を多めにしています。</p><button class="btn" onclick="startChapterQuiz('${l.chapter}')">章末チェックへ</button></section>` : `<section class="card soft"><b>理解チェックは章末でまとめて</b><p class="content">このレッスンでは流れを優先します。用語はタップして確認できます。</p></section>`}<button class="btn secondary" onclick="completeLesson()">${isChapterEnd?'チェックはあとで、次の章へ':'次のレッスンへ'}</button></main>${nav('学習')}`;
}
function startChapterQuiz(chapter){ sessionStorage.setItem(`chapterQidx_${chapter}`,'0'); location.href=`quiz.html?chapter=${encodeURIComponent(chapter)}`; }
function completeLesson(){ let s=getState(); if(!s.done.includes(s.lesson)) s.done.push(s.lesson); s.lesson=Math.min(s.lesson+1,lessons.length-1); s.xp+=10; setState(s); location.href='study.html'; }
function studyQuestionsForLesson(l){ if(!l) return []; const termSet=new Set(l.terms||[]); return questions.filter(q=>q.area===l.chapter && (q.q.includes(l.title.split('：')[0]) || (q.choices||[]).some(c=>[...termSet].some(t=>c.includes(t))) || [...termSet].some(t=>q.q.includes(t)))); }
function getQuizPool(){
 const params=new URLSearchParams(location.search);
 if(params.get('mode')==='mock') return mockQuestions;
 if(params.get('mode')==='random') return shuffle(questions).slice(0,20);
 if(params.get('type')) return questions.filter(q=>q.type===params.get('type'));
 if(params.get('area')) return questions.filter(q=>q.area===params.get('area'));
 if(params.get('chapter')) return questions.filter(q=>q.area===params.get('chapter'));
 if(params.get('lesson')!==null){ const l=lessons[Number(params.get('lesson'))]; const pool=studyQuestionsForLesson(l); return pool.length?pool:questions.filter(q=>q.area===l.chapter); }
 return questions;
}
function renderQuizStart(){
 const areas=[...new Set(questions.map(q=>q.area))]; const types=[...new Set(questions.map(q=>q.type))];
 document.body.innerHTML=`<main class="app">${header()}<section class="hero"><h1>問題演習</h1><p class="sub">章・ジャンルを選んで取り組めます。Chapter1は完成品質βとして、本番寄せケース問題を増やしました。</p><button class="btn" onclick="sessionStorage.setItem('randomQidx','0');location.href='quiz.html?mode=random'">ランダム20問</button></section><section class="card"><b>章から選ぶ</b>${areas.map(a=>`<button class="quiz-option" onclick="sessionStorage.setItem('areaQidx_${a}','0');location.href='quiz.html?area=${encodeURIComponent(a)}'">${a}（${questions.filter(q=>q.area===a).length}問）</button>`).join('')}</section><section class="card"><b>ジャンルから選ぶ</b>${types.map(t=>`<button class="quiz-option" onclick="sessionStorage.setItem('typeQidx_${t}','0');location.href='quiz.html?type=${encodeURIComponent(t)}'">${typeLabel(t)}（${questions.filter(q=>q.type===t).length}問）</button>`).join('')}</section></main>${nav('問題')}`;
}
function typeLabel(t){ const m={case:'ケース',compare:'比較',definition:'定義',model:'モデル',background:'背景',data:'データ',ai:'AI',design:'UXデザイン',growth:'グロース',intelligence:'UXインテリジェンス',trap:'ひっかけ','official-like':'公式風',summary:'総合',method:'調査',accessibility:'アクセシビリティ'}; return m[t]||t; }
function quizKeyFromParams(params){ const mode=params.get('mode'), lesson=params.get('lesson'), area=params.get('area'), chapter=params.get('chapter'), type=params.get('type'); return mode==='mock' ? 'mockQidx' : mode==='random' ? 'randomQidx' : area ? `areaQidx_${area}` : chapter ? `chapterQidx_${chapter}` : type ? `typeQidx_${type}` : `lessonQidx_${lesson}`; }
function renderQuiz(){
 const params=new URLSearchParams(location.search); const mode=params.get('mode'); const lesson=params.get('lesson'); const area=params.get('area'); const chapter=params.get('chapter'); const type=params.get('type');
 if(!mode && lesson===null && !area && !chapter && !type) return renderQuizStart();
 const pool=getQuizPool(); let key=quizKeyFromParams(params); let qi=Number(sessionStorage.getItem(key)||0);
 if(mode==='mock' && qi>=pool.length) return renderMockResult();
 const limit = (chapter || lesson!==null) ? Math.min(chapter==='UX概論'?12:5, pool.length) : pool.length;
 if((chapter || lesson!==null) && qi>=limit){ let s=getState(); if(lesson!==null){ const li=Number(lesson); if(!s.done.includes(li)) s.done.push(li); s.lesson=Math.max(s.lesson, Math.min(li+1, lessons.length-1)); } if(chapter){ const ch=chapters.find(c=>c.title===chapter); if(ch){ ch.lessons.forEach(id=>{ const di=lessons.findIndex(l=>l.id===id); if(di>=0 && !s.done.includes(di)) s.done.push(di); }); const lastIdx=lessons.findIndex(l=>l.id===ch.lessons[ch.lessons.length-1]); s.lesson=Math.min(lastIdx+1,lessons.length-1); } } setState(s); return location.href='study.html'; }
 qi=qi%pool.length; const q=pool[qi]; const order=shuffle(q.choices.map((c,i)=>({c,i}))); window.currentQ=q; window.quizKey=key; window.quizAnswered=false; window.quizMode=mode||'';
 const label=mode==='mock'?'ミニ模試':chapter?'章末チェック':lesson!==null?'レッスン確認':area?`${area} 演習`:type?`${typeLabel(type)} 演習`:'ランダム演習';
 document.body.innerHTML=`<main class="app">${header()}<section class="card"><div class="small">${label} / ${q.area} / ${typeLabel(q.type)}</div><h1 class="lesson-title">Q${qi+1}${mode==='mock'?` / ${pool.length}`:''}</h1><p class="content question-text">${q.q}</p><div id="opts">${order.map(o=>`<button class="quiz-option" onclick="answer(${o.i},this)">${o.c}</button>`).join('')}</div><div id="result"></div></section><button id="nextBtn" class="btn secondary" onclick="nextQ()" disabled>回答すると次へ進めます</button></main>${nav('問題')}`;
}
function answer(i,btn){ const q=window.currentQ; if(window.quizAnswered) return; window.quizAnswered=true; const correct=i===q.answer; document.querySelectorAll('.quiz-option').forEach(b=>b.disabled=true); btn.classList.add(correct?'correct':'wrong'); recordAnswer(q,correct); if(window.quizMode==='mock'){ const arr=JSON.parse(sessionStorage.getItem('mockResults')||'[]'); arr.push({id:q.id,correct,area:q.area}); sessionStorage.setItem('mockResults',JSON.stringify(arr)); } const nb=document.getElementById('nextBtn'); if(nb){ nb.disabled=false; nb.textContent='次の問題'; } document.getElementById('result').innerHTML=`<div class="explain"><b>${correct?'正解。':'惜しい。'}</b><br>${q.explain}${q.why?`<br><br><b>他の選択肢が最適ではない理由</b><br>${q.why}`:''}<br><br><b>正答</b><br>${q.choices[q.answer]}</div>`; }
function nextQ(){ if(!window.quizAnswered){ showToast('先に選択肢を選んでください'); return; } const key=window.quizKey||'freeQidx'; sessionStorage.setItem(key,Number(sessionStorage.getItem(key)||0)+1); location.href=location.pathname.split('/').pop()+location.search; }

function renderMock(){ sessionStorage.removeItem('mockQidx'); sessionStorage.removeItem('mockResults'); document.body.innerHTML=`<main class="app">${header()}<section class="hero"><h1>ミニ模試 β</h1><p class="sub">まずは10問。通常問題とは別の模試用ケースで、本番っぽい判断を確認します。</p><button class="btn" onclick="sessionStorage.setItem('mockQidx','0');sessionStorage.setItem('mockResults','[]');location.href='quiz.html?mode=mock'">開始する</button></section><section class="card"><b>v1.0βの位置づけ</b><p class="content">まだ本番100問模試ではありません。Chapter1の理解確認用に近いミニ模試です。</p></section></main>${nav('模試')}`; }
function renderMockResult(){ const s=getState(); const results=JSON.parse(sessionStorage.getItem('mockResults')||'[]'); const correct=results.filter(r=>r.correct).length; const rate=pct(correct, mockQuestions.length); s.mock={rate,at:Date.now()}; setState(s); document.body.innerHTML=`<main class="app">${header()}<section class="hero"><h1>ミニ模試終了</h1><p class="sub">今回の正答率：${rate}%（${correct}/${mockQuestions.length}問）<br>現在の合格予測：${passRate(s)}%</p><button class="btn" onclick="sessionStorage.removeItem('mockQidx');sessionStorage.removeItem('mockResults');location.href='mock.html'">もう一度</button></section><section class="card"><b>次に見るところ</b><p class="content">Chapter1で80%未満なら、比較カードとUX概論の章末チェックをもう一度。</p></section></main>${nav('模試')}`; }
function renderReview(){ const s=getState(); const wrongIds=s.wrong.slice(-12).reverse(); document.body.innerHTML=`<main class="app">${header()}<section class="hero"><h1>復習</h1><p class="sub">間違えた問題を見直します。まずはChapter1の誤答を優先。</p></section><section class="list">${wrongIds.map(id=>{const q=questions.find(x=>x.id===id)||mockQuestions.find(x=>x.id===id); return q?`<div class="row"><span>${q.area}</span><b>${q.q}</b></div>`:''}).join('')||'<div class="card">まだ復習対象はありません。</div>'}</section></main>${nav('復習')}`; }
function renderSearch(){ document.body.innerHTML=`<main class="app">${header()}<section class="hero"><h1>対応表と比較カード</h1><p class="sub">Chapter1はシラバスのUX概論系をβ完成品質として整理。ここから全章へ横展開します。</p></section><section class="card"><b>シラバス対応表</b>${syllabusMap.map(s=>`<div class="row"><div><b>${s.title}</b><p>${s.covered.join(' / ')}</p></div><span class="tag">${s.status}</span></div>`).join('')}</section><section class="hero"><h1>比較カード</h1><p class="sub">混同しやすい概念を左右で整理。</p></section>${comparisons.map(c=>`<section class="card"><div class="compare"><div class="box"><b>${c.a}</b><p>${c.left}</p></div><div class="box"><b>${c.b}</b><p>${c.right}</p></div></div></section>`).join('')}<section class="card"><b>参考</b>${references.map(r=>`<div class="row"><span>公式</span><a href="${r.url}" target="_blank"><b>${r.label}</b></a></div>`).join('')}</section></main>${nav('探す')}`; }
function renderProfile(){ const s=getState(); const st=answerStats(s); const byArea={}; Object.entries(s.answers||{}).forEach(([id,a])=>{ byArea[a.area]=byArea[a.area]||{n:0,c:0}; byArea[a.area].n++; if(a.lastCorrect) byArea[a.area].c++; }); const weak=Object.entries(byArea).map(([area,v])=>({area,rate:pct(v.c,v.n),n:v.n})).sort((a,b)=>a.rate-b.rate).slice(0,3); document.body.innerHTML=`<main class="app">${header()}<section class="hero"><h1>記録</h1><p class="sub">完了 ${s.done.length}/${lessons.length} レッスン<br>直近正答率 ${st.accuracy||0}% / 回答済み ${st.answered}問</p><div class="meter"><div class="bar" style="width:${pct(s.done.length,lessons.length)}%"></div></div></section><section class="grid"><div class="mini"><b>${passRate(s)}%</b><span class="small">合格予測<br>${passNote(s)}</span></div><div class="mini"><b>${s.wrong.length}</b><span class="small">復習待ち</span></div><div class="mini"><b>${st.totalAttempts}</b><span class="small">総回答数</span></div><div class="mini"><b>${s.xp}</b><span class="small">XP</span></div></section><section class="card"><b>苦手候補</b>${weak.length?weak.map(w=>`<div class="row"><span>${w.area}</span><b>${w.rate}%</b></div>`).join(''):'<p class="content">まだ問題数が少ないため、もう少し解くと表示されます。</p>'}</section><button class="btn ghost" onclick="reset()">進捗を初期化</button></main>${nav('記録')}`; }
